import type { BackendListing } from '@/types/bff'

// ─── Domain types ─────────────────────────────────────────────────────────────

/** A card the user needs to buy (not owned) */
export interface MissingCard {
  catalogSku: string
  cardName: string
  quantity: number
}

/** Optimization strategy */
export type OptimizationMode = 'cheapest' | 'fewest-sellers' | 'best-value'

/** A single card assigned to a specific listing/seller */
export interface SellerAssignment {
  catalogSku: string
  cardName: string
  quantity: number
  listing: BackendListing
}

/** Group of cards assigned to the same seller */
export interface SellerGroup {
  sellerId: string
  sellerName: string
  sellerRating?: number
  sellerReviewCount?: number
  assignments: SellerAssignment[]
  subtotal: number          // cents — sum of (price * quantity) for this seller
  shippingCost: number      // cents — one-time shipping cost for this seller
  total: number             // cents — subtotal + shippingCost
}

/** Full result of the optimization algorithm */
export interface OptimizationResult {
  mode: OptimizationMode
  sellerGroups: SellerGroup[]
  totalCost: number         // cents — sum of all seller group totals
  totalShipping: number     // cents — sum of all seller shipping costs
  totalCards: number        // count of cards successfully assigned
  unassignedCards: MissingCard[]  // cards with no available listings
  timestamp: number         // Date.now() when result was computed
}

// ─── BFF request/response ─────────────────────────────────────────────────────

/** POST /api/optimizer/listings request body */
export interface OptimizerListingsRequest {
  catalogSkus: string[]
}

/** POST /api/optimizer/listings response body */
export interface OptimizerListingsResponse {
  listings: Record<string, BackendListing[]>
  errors: string[]          // SKUs that failed to fetch
  timestamp: number
}

