import type { BackendListing } from '@/types/bff'
import type {
  MissingCard,
  OptimizationMode,
  OptimizationResult,
  SellerAssignment,
  SellerGroup,
} from './types'

// ─── Shipping cost derivation ─────────────────────────────────────────────────

const SHIPPING_RATES: Record<string, number> = {
  standard: 399,
  tracked: 599,
}
const DEFAULT_SHIPPING = 399

/**
 * Derive shipping cost in cents from a listing.
 * Prefers explicit shippingCost, falls back to method-based flat rate.
 */
export function deriveShippingCost(
  shippingMethod: string,
  shippingCost?: number,
): number {
  if (shippingCost !== undefined && shippingCost !== null) return shippingCost
  return SHIPPING_RATES[shippingMethod] ?? DEFAULT_SHIPPING
}

function getShippingCost(listing: BackendListing): number {
  return deriveShippingCost(listing.shippingMethod, listing.shippingCost)
}

// ─── Internal types ───────────────────────────────────────────────────────────

/** Deduplicated card with listing count for scarcity sort */
interface CardWorkItem {
  catalogSku: string
  cardName: string
  quantity: number
}

/** Tracks what a seller has been assigned so far */
interface SellerAccumulator {
  sellerId: string
  sellerName: string
  sellerRating?: number
  sellerReviewCount?: number
  assignments: SellerAssignment[]
  shippingCost: number // fixed per-seller shipping (set on first assignment)
}

// ─── Pre-processing ───────────────────────────────────────────────────────────

/**
 * Deduplicate missing cards by catalogSku, summing quantities.
 */
function deduplicateCards(cards: MissingCard[]): CardWorkItem[] {
  const map = new Map<string, CardWorkItem>()
  for (const card of cards) {
    const existing = map.get(card.catalogSku)
    if (existing) {
      existing.quantity += card.quantity
    } else {
      map.set(card.catalogSku, {
        catalogSku: card.catalogSku,
        cardName: card.cardName,
        quantity: card.quantity,
      })
    }
  }
  return Array.from(map.values())
}

/**
 * Sort cards by listing scarcity (ascending), then by catalogSku for determinism.
 */
function sortByScarcity(
  cards: CardWorkItem[],
  listingsByCard: Record<string, BackendListing[]>,
): CardWorkItem[] {
  return [...cards].sort((a, b) => {
    const aCount = listingsByCard[a.catalogSku]?.length ?? 0
    const bCount = listingsByCard[b.catalogSku]?.length ?? 0
    if (aCount !== bCount) return aCount - bCount
    return a.catalogSku.localeCompare(b.catalogSku)
  })
}

// ─── Greedy assignment core ───────────────────────────────────────────────────

/**
 * Assign a card to sellers using the cheapest marginal cost strategy.
 * Handles quantity splitting when a single listing can't fulfill demand.
 */
function assignCardCheapest(
  card: CardWorkItem,
  listings: BackendListing[],
  sellers: Map<string, SellerAccumulator>,
  remainingQuantities: Map<string, number>,
): void {
  let needed = card.quantity

  while (needed > 0) {
    let bestListing: BackendListing | null = null
    let bestCost = Infinity
    let bestQty = 0

    for (const listing of listings) {
      const available = remainingQuantities.get(listing.id) ?? 0
      if (available <= 0) continue

      const qty = Math.min(needed, available)
      const isNewSeller = !sellers.has(listing.sellerId)
      const shippingIncrement = isNewSeller ? getShippingCost(listing) : 0
      const marginalCost = listing.price * qty + shippingIncrement

      if (
        marginalCost < bestCost ||
        (marginalCost === bestCost && listing.sellerId < (bestListing?.sellerId ?? ''))
      ) {
        bestListing = listing
        bestCost = marginalCost
        bestQty = qty
      }
    }

    if (!bestListing) break // no more listings available

    // Assign
    const sellerId = bestListing.sellerId
    if (!sellers.has(sellerId)) {
      sellers.set(sellerId, {
        sellerId,
        sellerName: bestListing.sellerName,
        sellerRating: bestListing.sellerRating,
        sellerReviewCount: bestListing.sellerReviewCount,
        assignments: [],
        shippingCost: getShippingCost(bestListing),
      })
    }

    sellers.get(sellerId)!.assignments.push({
      catalogSku: card.catalogSku,
      cardName: card.cardName,
      quantity: bestQty,
      listing: bestListing,
    })

    // Decrease remaining stock for this listing
    remainingQuantities.set(
      bestListing.id,
      (remainingQuantities.get(bestListing.id) ?? 0) - bestQty,
    )
    needed -= bestQty
  }
}

/**
 * Assign a card preferring sellers already in the result set.
 * Among existing sellers, pick cheapest. If none have the card, add cheapest new seller.
 */
function assignCardFewestSellers(
  card: CardWorkItem,
  listings: BackendListing[],
  sellers: Map<string, SellerAccumulator>,
  remainingQuantities: Map<string, number>,
): void {
  let needed = card.quantity

  while (needed > 0) {
    // Separate into existing vs new sellers
    let bestListing: BackendListing | null = null
    let bestCost = Infinity
    let bestQty = 0
    let foundExisting = false

    // First pass: existing sellers only
    for (const listing of listings) {
      const available = remainingQuantities.get(listing.id) ?? 0
      if (available <= 0) continue
      if (!sellers.has(listing.sellerId)) continue

      const qty = Math.min(needed, available)
      const cost = listing.price * qty // no shipping — seller already in set

      if (
        cost < bestCost ||
        (cost === bestCost && listing.sellerId < (bestListing?.sellerId ?? ''))
      ) {
        bestListing = listing
        bestCost = cost
        bestQty = qty
        foundExisting = true
      }
    }

    // Second pass: new sellers (only if no existing seller has this card)
    if (!foundExisting) {
      for (const listing of listings) {
        const available = remainingQuantities.get(listing.id) ?? 0
        if (available <= 0) continue

        const qty = Math.min(needed, available)
        const cost = listing.price * qty + getShippingCost(listing)

        if (
          cost < bestCost ||
          (cost === bestCost && listing.sellerId < (bestListing?.sellerId ?? ''))
        ) {
          bestListing = listing
          bestCost = cost
          bestQty = qty
        }
      }
    }

    if (!bestListing) break

    const sellerId = bestListing.sellerId
    if (!sellers.has(sellerId)) {
      sellers.set(sellerId, {
        sellerId,
        sellerName: bestListing.sellerName,
        sellerRating: bestListing.sellerRating,
        sellerReviewCount: bestListing.sellerReviewCount,
        assignments: [],
        shippingCost: getShippingCost(bestListing),
      })
    }

    sellers.get(sellerId)!.assignments.push({
      catalogSku: card.catalogSku,
      cardName: card.cardName,
      quantity: bestQty,
      listing: bestListing,
    })

    remainingQuantities.set(
      bestListing.id,
      (remainingQuantities.get(bestListing.id) ?? 0) - bestQty,
    )
    needed -= bestQty
  }
}

// ─── Result assembly ──────────────────────────────────────────────────────────

function buildResult(
  mode: OptimizationMode,
  sellers: Map<string, SellerAccumulator>,
  unassignedCards: MissingCard[],
  listingsByCard: Record<string, BackendListing[]>,
  allCards: CardWorkItem[],
): OptimizationResult {
  const sellerGroups: SellerGroup[] = Array.from(sellers.values())
    .map((acc) => {
      const subtotal = acc.assignments.reduce(
        (sum, a) => sum + a.listing.price * a.quantity,
        0,
      )
      return {
        sellerId: acc.sellerId,
        sellerName: acc.sellerName,
        sellerRating: acc.sellerRating,
        sellerReviewCount: acc.sellerReviewCount,
        assignments: acc.assignments,
        subtotal,
        shippingCost: acc.shippingCost,
        total: subtotal + acc.shippingCost,
      }
    })
    .sort((a, b) => a.sellerId.localeCompare(b.sellerId)) // deterministic order

  const totalCost = sellerGroups.reduce((sum, g) => sum + g.total, 0)
  const totalShipping = sellerGroups.reduce((sum, g) => sum + g.shippingCost, 0)
  const totalCards = sellerGroups.reduce(
    (sum, g) => sum + g.assignments.reduce((s, a) => s + a.quantity, 0),
    0,
  )

  // Naive cost: cheapest per-card without shipping optimization
  // Each card picks its cheapest listing, shipping charged per-card (not amortized)
  const totalWithoutOptimization = computeNaiveCost(allCards, listingsByCard)
  const savings = Math.max(0, totalWithoutOptimization - totalCost)

  return {
    mode,
    sellerGroups,
    totalCost,
    totalShipping,
    totalCards,
    unassignedCards,
    totalWithoutOptimization,
    savings,
    timestamp: Date.now(),
  }
}

/**
 * Compute naive cost: for each card, pick cheapest listing price + that listing's
 * shipping cost, treating every card as a separate purchase (no seller grouping).
 */
function computeNaiveCost(
  cards: CardWorkItem[],
  listingsByCard: Record<string, BackendListing[]>,
): number {
  let total = 0
  for (const card of cards) {
    const listings = listingsByCard[card.catalogSku]
    if (!listings || listings.length === 0) continue

    // Sort by price ascending for cheapest-first allocation
    const sorted = [...listings].sort((a, b) => a.price - b.price)
    let needed = card.quantity

    for (const listing of sorted) {
      if (needed <= 0) break
      const qty = Math.min(needed, listing.quantity)
      // Naive: each pick pays its own shipping
      total += listing.price * qty + getShippingCost(listing)
      needed -= qty
    }
  }
  return total
}

// ─── Main optimizer ───────────────────────────────────────────────────────────

/**
 * Greedy cart optimizer. Pure function — no side effects.
 *
 * Finds optimal seller combinations for missing cards across three modes:
 * - cheapest: minimize total cost (price + amortized shipping)
 * - fewest-sellers: minimize seller count, breaking ties by price
 * - best-value: run cheapest, then try consolidating if cost increase < 15%
 */
export function optimizeCart(
  missingCards: MissingCard[],
  listingsByCard: Record<string, BackendListing[]>,
  mode: OptimizationMode,
): OptimizationResult {
  // Edge case: empty input
  if (!missingCards || missingCards.length === 0) {
    return {
      mode,
      sellerGroups: [],
      totalCost: 0,
      totalShipping: 0,
      totalCards: 0,
      unassignedCards: [],
      totalWithoutOptimization: 0,
      savings: 0,
      timestamp: Date.now(),
    }
  }

  // Pre-processing: deduplicate by catalogSku
  const deduped = deduplicateCards(missingCards)

  // Separate cards with no listings
  const unassignedCards: MissingCard[] = []
  const assignableCards: CardWorkItem[] = []

  for (const card of deduped) {
    const listings = listingsByCard[card.catalogSku]
    if (!listings || listings.length === 0) {
      unassignedCards.push({
        catalogSku: card.catalogSku,
        cardName: card.cardName,
        quantity: card.quantity,
      })
    } else {
      assignableCards.push(card)
    }
  }

  // Sort by scarcity (fewest listings first)
  const sorted = sortByScarcity(assignableCards, listingsByCard)

  if (mode === 'best-value') {
    return runBestValue(sorted, listingsByCard, unassignedCards, deduped)
  }

  // Build initial remaining-quantity map across all listings
  const remainingQuantities = buildRemainingQuantities(listingsByCard)
  const sellers = new Map<string, SellerAccumulator>()

  const assignFn =
    mode === 'cheapest' ? assignCardCheapest : assignCardFewestSellers

  for (const card of sorted) {
    const listings = listingsByCard[card.catalogSku] ?? []
    assignFn(card, listings, sellers, remainingQuantities)
  }

  return buildResult(mode, sellers, unassignedCards, listingsByCard, deduped)
}

/**
 * Best-value mode: run cheapest as baseline, then run fewest-sellers.
 * If fewest-sellers cost increase is < 15%, use it. Otherwise use cheapest.
 * Weighted: 0.7 * normalizedCost + 0.3 * normalizedSellerCount.
 */
function runBestValue(
  sorted: CardWorkItem[],
  listingsByCard: Record<string, BackendListing[]>,
  unassignedCards: MissingCard[],
  allCards: CardWorkItem[],
): OptimizationResult {
  // Run cheapest
  const cheapestQuantities = buildRemainingQuantities(listingsByCard)
  const cheapestSellers = new Map<string, SellerAccumulator>()
  for (const card of sorted) {
    assignCardCheapest(
      card,
      listingsByCard[card.catalogSku] ?? [],
      cheapestSellers,
      cheapestQuantities,
    )
  }
  const cheapestResult = buildResult(
    'cheapest',
    cheapestSellers,
    unassignedCards,
    listingsByCard,
    allCards,
  )

  // Run fewest-sellers
  const fewestQuantities = buildRemainingQuantities(listingsByCard)
  const fewestSellers = new Map<string, SellerAccumulator>()
  for (const card of sorted) {
    assignCardFewestSellers(
      card,
      listingsByCard[card.catalogSku] ?? [],
      fewestSellers,
      fewestQuantities,
    )
  }
  const fewestResult = buildResult(
    'fewest-sellers',
    fewestSellers,
    unassignedCards,
    listingsByCard,
    allCards,
  )

  // If cheapest has 0 cost, just return it
  if (cheapestResult.totalCost === 0) {
    return { ...cheapestResult, mode: 'best-value' }
  }

  // Check if fewest-sellers is within 15% cost increase
  const costIncrease =
    (fewestResult.totalCost - cheapestResult.totalCost) / cheapestResult.totalCost

  if (costIncrease <= 0.15) {
    // Fewest-sellers is close enough in cost — use it for fewer sellers
    return { ...fewestResult, mode: 'best-value' }
  }

  // Use weighted scoring: 0.7 * normalizedCost + 0.3 * normalizedSellerCount
  const maxCost = Math.max(cheapestResult.totalCost, fewestResult.totalCost)
  const maxSellers = Math.max(
    cheapestResult.sellerGroups.length,
    fewestResult.sellerGroups.length,
  )

  if (maxCost === 0 || maxSellers === 0) {
    return { ...cheapestResult, mode: 'best-value' }
  }

  const cheapestScore =
    0.7 * (cheapestResult.totalCost / maxCost) +
    0.3 * (cheapestResult.sellerGroups.length / maxSellers)
  const fewestScore =
    0.7 * (fewestResult.totalCost / maxCost) +
    0.3 * (fewestResult.sellerGroups.length / maxSellers)

  const winner = cheapestScore <= fewestScore ? cheapestResult : fewestResult
  return { ...winner, mode: 'best-value' }
}

/**
 * Build a map of listing ID → remaining quantity for all listings.
 */
function buildRemainingQuantities(
  listingsByCard: Record<string, BackendListing[]>,
): Map<string, number> {
  const map = new Map<string, number>()
  for (const listings of Object.values(listingsByCard)) {
    for (const listing of listings) {
      // If same listing appears under multiple SKUs (shouldn't, but be safe),
      // use the listing's own quantity
      map.set(listing.id, listing.quantity)
    }
  }
  return map
}

// ─── Diagnostics ──────────────────────────────────────────────────────────────

/**
 * Human-readable summary for diagnostics / logging.
 */
export function formatOptimizationSummary(result: OptimizationResult): string {
  const lines: string[] = []
  lines.push(
    `[cart-optimizer] Mode: ${result.mode} | ` +
      `${result.totalCards} cards from ${result.sellerGroups.length} seller(s) | ` +
      `Total: $${(result.totalCost / 100).toFixed(2)} ` +
      `(shipping: $${(result.totalShipping / 100).toFixed(2)}) | ` +
      `Savings: $${(result.savings / 100).toFixed(2)}`,
  )

  if (result.unassignedCards.length > 0) {
    lines.push(
      `[cart-optimizer] ${result.unassignedCards.length} card(s) unavailable: ` +
        result.unassignedCards.map((c) => c.cardName).join(', '),
    )
  }

  for (const group of result.sellerGroups) {
    lines.push(
      `  ${group.sellerName} (${group.assignments.length} cards): ` +
        `$${(group.subtotal / 100).toFixed(2)} + ` +
        `$${(group.shippingCost / 100).toFixed(2)} ship = ` +
        `$${(group.total / 100).toFixed(2)}`,
    )
  }

  return lines.join('\n')
}

import { describe, it, expect } from 'vitest'
import {
  optimizeCart,
  deriveShippingCost,
  formatOptimizationSummary,
} from '../optimizeCart'
import type { BackendListing } from '@/types/bff'
import type { MissingCard, OptimizationResult } from '../types'

// ─── Test helpers ─────────────────────────────────────────────────────────────

function makeListing(overrides: Partial<BackendListing> & { id: string; catalogSku: string; sellerId: string }): BackendListing {
  return {
    condition: 'NM',
    language: 'English',
    finish: 'nonfoil',
    price: 100,
    currency: 'usd',
    quantity: 10,
    shippingMethod: 'standard',
    sellerName: `Seller ${overrides.sellerId}`,
    sellerType: 'consumer',
    ...overrides,
  }
}

function makeCard(sku: string, name: string, quantity = 1): MissingCard {
  return { catalogSku: sku, cardName: name, quantity }
}

// ─── deriveShippingCost ───────────────────────────────────────────────────────

describe('deriveShippingCost', () => {
  it('returns explicit shippingCost when provided', () => {
    expect(deriveShippingCost('standard', 250)).toBe(250)
  })

  it('returns 399 for standard shipping method', () => {
    expect(deriveShippingCost('standard')).toBe(399)
  })

  it('returns 599 for tracked shipping method', () => {
    expect(deriveShippingCost('tracked')).toBe(599)
  })

  it('returns 399 for unknown shipping method', () => {
    expect(deriveShippingCost('express')).toBe(399)
    expect(deriveShippingCost('')).toBe(399)
  })

  it('prefers explicit value of 0 over method-based', () => {
    expect(deriveShippingCost('tracked', 0)).toBe(0)
  })
})

// ─── optimizeCart ─────────────────────────────────────────────────────────────

describe('optimizeCart', () => {
  // ── Empty input ───────────────────────────────────────────────────────────

  it('returns empty result for empty input', () => {
    const result = optimizeCart([], {}, 'cheapest')
    expect(result.sellerGroups).toEqual([])
    expect(result.totalCost).toBe(0)
    expect(result.totalCards).toBe(0)
    expect(result.unassignedCards).toEqual([])
    expect(result.savings).toBe(0)
    expect(result.mode).toBe('cheapest')
  })

  // ── No listings for a card ────────────────────────────────────────────────

  it('reports cards with no listings in unassignedCards', () => {
    const cards = [makeCard('SKU-A', 'Card A'), makeCard('SKU-B', 'Card B')]
    const listings = {
      'SKU-A': [makeListing({ id: 'l1', catalogSku: 'SKU-A', sellerId: 's1', price: 200 })],
      // SKU-B has no listings
    }
    const result = optimizeCart(cards, listings, 'cheapest')

    expect(result.unassignedCards).toHaveLength(1)
    expect(result.unassignedCards[0].catalogSku).toBe('SKU-B')
    expect(result.totalCards).toBe(1)
  })

  // ── Cheapest mode: 3 cards × 3 sellers ────────────────────────────────────

  it('cheapest mode picks lowest total cost including shipping amortization', () => {
    const cards = [
      makeCard('SKU-A', 'Card A'),
      makeCard('SKU-B', 'Card B'),
      makeCard('SKU-C', 'Card C'),
    ]

    // Seller s1: has A+B (cheap cards, one shipping charge)
    // Seller s2: has A+C (slightly cheaper individual prices)
    // Seller s3: has B+C (expensive)
    const listings: Record<string, BackendListing[]> = {
      'SKU-A': [
        makeListing({ id: 'a1', catalogSku: 'SKU-A', sellerId: 's1', price: 200, sellerName: 'Seller 1' }),
        makeListing({ id: 'a2', catalogSku: 'SKU-A', sellerId: 's2', price: 180, sellerName: 'Seller 2' }),
      ],
      'SKU-B': [
        makeListing({ id: 'b1', catalogSku: 'SKU-B', sellerId: 's1', price: 300, sellerName: 'Seller 1' }),
        makeListing({ id: 'b3', catalogSku: 'SKU-B', sellerId: 's3', price: 350, sellerName: 'Seller 3' }),
      ],
      'SKU-C': [
        makeListing({ id: 'c2', catalogSku: 'SKU-C', sellerId: 's2', price: 150, sellerName: 'Seller 2' }),
        makeListing({ id: 'c3', catalogSku: 'SKU-C', sellerId: 's3', price: 400, sellerName: 'Seller 3' }),
      ],
    }

    const result = optimizeCart(cards, listings, 'cheapest')

    expect(result.mode).toBe('cheapest')
    expect(result.totalCards).toBe(3)
    // Algorithm should factor shipping amortization
    // All groups should have valid totals
    for (const group of result.sellerGroups) {
      expect(group.total).toBe(group.subtotal + group.shippingCost)
    }
    // Total cost must equal sum of all group totals
    const expectedTotal = result.sellerGroups.reduce((s, g) => s + g.total, 0)
    expect(result.totalCost).toBe(expectedTotal)
  })

  // ── Fewest-sellers mode ───────────────────────────────────────────────────

  it('fewest-sellers mode consolidates to fewer sellers even if marginally more expensive', () => {
    const cards = [
      makeCard('SKU-A', 'Card A'),
      makeCard('SKU-B', 'Card B'),
      makeCard('SKU-C', 'Card C'),
    ]

    // Seller s1 has all 3 cards at moderate prices
    // Seller s2 has card A much cheaper
    const listings: Record<string, BackendListing[]> = {
      'SKU-A': [
        makeListing({ id: 'a1', catalogSku: 'SKU-A', sellerId: 's1', price: 300, sellerName: 'Seller 1' }),
        makeListing({ id: 'a2', catalogSku: 'SKU-A', sellerId: 's2', price: 100, sellerName: 'Seller 2' }),
      ],
      'SKU-B': [
        makeListing({ id: 'b1', catalogSku: 'SKU-B', sellerId: 's1', price: 200, sellerName: 'Seller 1' }),
      ],
      'SKU-C': [
        makeListing({ id: 'c1', catalogSku: 'SKU-C', sellerId: 's1', price: 250, sellerName: 'Seller 1' }),
      ],
    }

    const result = optimizeCart(cards, listings, 'fewest-sellers')

    // SKU-B and SKU-C can only come from s1
    // Fewest-sellers should then prefer s1 for SKU-A too (already in set)
    expect(result.sellerGroups).toHaveLength(1)
    expect(result.sellerGroups[0].sellerId).toBe('s1')
    expect(result.totalCards).toBe(3)
  })

  // ── Best-value mode ───────────────────────────────────────────────────────

  it('best-value mode produces balanced result between cheapest and fewest', () => {
    const cards = [
      makeCard('SKU-A', 'Card A'),
      makeCard('SKU-B', 'Card B'),
      makeCard('SKU-C', 'Card C'),
    ]

    // Seller s1 has all 3 at moderate prices
    // Seller s2 has A cheaper, s3 has B cheaper
    const listings: Record<string, BackendListing[]> = {
      'SKU-A': [
        makeListing({ id: 'a1', catalogSku: 'SKU-A', sellerId: 's1', price: 500, sellerName: 'Seller 1' }),
        makeListing({ id: 'a2', catalogSku: 'SKU-A', sellerId: 's2', price: 100, sellerName: 'Seller 2' }),
      ],
      'SKU-B': [
        makeListing({ id: 'b1', catalogSku: 'SKU-B', sellerId: 's1', price: 500, sellerName: 'Seller 1' }),
        makeListing({ id: 'b3', catalogSku: 'SKU-B', sellerId: 's3', price: 100, sellerName: 'Seller 3' }),
      ],
      'SKU-C': [
        makeListing({ id: 'c1', catalogSku: 'SKU-C', sellerId: 's1', price: 500, sellerName: 'Seller 1' }),
        makeListing({ id: 'c2', catalogSku: 'SKU-C', sellerId: 's2', price: 100, sellerName: 'Seller 2' }),
      ],
    }

    const result = optimizeCart(cards, listings, 'best-value')

    expect(result.mode).toBe('best-value')
    expect(result.totalCards).toBe(3)
    // Should produce a valid result with at least some savings calculation
    expect(result.totalCost).toBeGreaterThan(0)
    expect(typeof result.savings).toBe('number')
    // best-value should find a middle ground
    // In this case cheapest uses 3 sellers (300 cards + 3*399 ship = 1497)
    // fewest uses 1 seller (1500 cards + 399 ship = 1899)
    // cost increase = (1899-1497)/1497 = 26.9% > 15%, so weighted score decides
  })

  // ── Shipping amortization ─────────────────────────────────────────────────

  it('charges shipping only once per seller, not per card', () => {
    const cards = [
      makeCard('SKU-A', 'Card A'),
      makeCard('SKU-B', 'Card B'),
    ]

    const listings: Record<string, BackendListing[]> = {
      'SKU-A': [
        makeListing({ id: 'a1', catalogSku: 'SKU-A', sellerId: 's1', price: 100, sellerName: 'Seller 1' }),
      ],
      'SKU-B': [
        makeListing({ id: 'b1', catalogSku: 'SKU-B', sellerId: 's1', price: 100, sellerName: 'Seller 1' }),
      ],
    }

    const result = optimizeCart(cards, listings, 'cheapest')

    expect(result.sellerGroups).toHaveLength(1)
    expect(result.sellerGroups[0].shippingCost).toBe(399) // one charge
    expect(result.totalShipping).toBe(399) // not 2*399
    expect(result.totalCost).toBe(200 + 399) // 2 cards * 100 + one shipping
  })

  // ── Scarcity ordering ─────────────────────────────────────────────────────

  it('assigns scarce cards first to preserve their only listing', () => {
    // Card A: only 1 listing from s1
    // Card B: 2 listings from s1 and s2
    // Both need 1 copy. s1 has qty 1 for both.
    // If B is assigned first and takes s1, A has no listing.
    // Scarcity ordering ensures A (1 listing) is assigned first.
    const cards = [
      makeCard('SKU-B', 'Card B'), // intentionally listed first to test reordering
      makeCard('SKU-A', 'Card A'),
    ]

    const listings: Record<string, BackendListing[]> = {
      'SKU-A': [
        makeListing({ id: 'a1', catalogSku: 'SKU-A', sellerId: 's1', price: 100, quantity: 1, sellerName: 'Seller 1' }),
      ],
      'SKU-B': [
        makeListing({ id: 'b1', catalogSku: 'SKU-B', sellerId: 's1', price: 100, quantity: 1, sellerName: 'Seller 1' }),
        makeListing({ id: 'b2', catalogSku: 'SKU-B', sellerId: 's2', price: 200, quantity: 1, sellerName: 'Seller 2' }),
      ],
    }

    const result = optimizeCart(cards, listings, 'cheapest')

    // A should be assigned to s1 (only option)
    // B should go to s2 (since s1's listing is consumed by A — qty 1)
    expect(result.totalCards).toBe(2)
    expect(result.unassignedCards).toHaveLength(0)

    const s1Group = result.sellerGroups.find((g) => g.sellerId === 's1')
    const s2Group = result.sellerGroups.find((g) => g.sellerId === 's2')
    expect(s1Group?.assignments[0].catalogSku).toBe('SKU-A')
    expect(s2Group?.assignments[0].catalogSku).toBe('SKU-B')
  })

  // ── Quantity splitting ────────────────────────────────────────────────────

  it('splits across sellers when single seller cannot fulfill quantity', () => {
    const cards = [makeCard('SKU-A', 'Card A', 4)]

    const listings: Record<string, BackendListing[]> = {
      'SKU-A': [
        makeListing({ id: 'a1', catalogSku: 'SKU-A', sellerId: 's1', price: 100, quantity: 2, sellerName: 'Seller 1' }),
        makeListing({ id: 'a2', catalogSku: 'SKU-A', sellerId: 's2', price: 150, quantity: 3, sellerName: 'Seller 2' }),
      ],
    }

    const result = optimizeCart(cards, listings, 'cheapest')

    expect(result.totalCards).toBe(4)
    // s1 provides 2 (cheapest), s2 provides remaining 2
    const s1 = result.sellerGroups.find((g) => g.sellerId === 's1')
    const s2 = result.sellerGroups.find((g) => g.sellerId === 's2')
    expect(s1?.assignments[0].quantity).toBe(2)
    expect(s2?.assignments[0].quantity).toBe(2)
    // Shipping charged for each seller
    expect(result.totalShipping).toBe(399 + 399)
  })

  // ── Single seller has everything ──────────────────────────────────────────

  it('assigns all cards to single seller with one shipping charge', () => {
    const cards = [
      makeCard('SKU-A', 'Card A'),
      makeCard('SKU-B', 'Card B'),
      makeCard('SKU-C', 'Card C'),
    ]

    const listings: Record<string, BackendListing[]> = {
      'SKU-A': [makeListing({ id: 'a1', catalogSku: 'SKU-A', sellerId: 's1', price: 200, sellerName: 'Seller 1' })],
      'SKU-B': [makeListing({ id: 'b1', catalogSku: 'SKU-B', sellerId: 's1', price: 300, sellerName: 'Seller 1' })],
      'SKU-C': [makeListing({ id: 'c1', catalogSku: 'SKU-C', sellerId: 's1', price: 150, sellerName: 'Seller 1' })],
    }

    const result = optimizeCart(cards, listings, 'cheapest')

    expect(result.sellerGroups).toHaveLength(1)
    expect(result.sellerGroups[0].sellerId).toBe('s1')
    expect(result.totalShipping).toBe(399)
    expect(result.totalCost).toBe(200 + 300 + 150 + 399)
    expect(result.totalCards).toBe(3)
  })

  // ── All same price ────────────────────────────────────────────────────────

  it('produces deterministic results when all prices are identical', () => {
    const cards = [makeCard('SKU-A', 'Card A'), makeCard('SKU-B', 'Card B')]

    const listings: Record<string, BackendListing[]> = {
      'SKU-A': [
        makeListing({ id: 'a1', catalogSku: 'SKU-A', sellerId: 's2', price: 100, sellerName: 'Seller 2' }),
        makeListing({ id: 'a2', catalogSku: 'SKU-A', sellerId: 's1', price: 100, sellerName: 'Seller 1' }),
      ],
      'SKU-B': [
        makeListing({ id: 'b1', catalogSku: 'SKU-B', sellerId: 's2', price: 100, sellerName: 'Seller 2' }),
        makeListing({ id: 'b2', catalogSku: 'SKU-B', sellerId: 's1', price: 100, sellerName: 'Seller 1' }),
      ],
    }

    // Run twice — result should be identical
    const result1 = optimizeCart(cards, listings, 'cheapest')
    const result2 = optimizeCart(cards, listings, 'cheapest')

    // Same seller groups, same assignments
    expect(result1.sellerGroups.length).toBe(result2.sellerGroups.length)
    for (let i = 0; i < result1.sellerGroups.length; i++) {
      expect(result1.sellerGroups[i].sellerId).toBe(result2.sellerGroups[i].sellerId)
      expect(result1.sellerGroups[i].assignments.length).toBe(
        result2.sellerGroups[i].assignments.length,
      )
    }

    // With same prices + same shipping, tiebreaker by sellerId (s1 < s2)
    // First card assigned picks s1 (marginal cost = 100 + 399 for both, s1 < s2)
    // Second card: s1 already in set → marginal cost = 100 (no shipping), vs s2 = 100 + 399
    // So both should go to s1
    expect(result1.sellerGroups).toHaveLength(1)
    expect(result1.sellerGroups[0].sellerId).toBe('s1')
  })

  // ── Savings calculation ───────────────────────────────────────────────────

  it('calculates savings comparing optimized vs naive per-card cost', () => {
    const cards = [
      makeCard('SKU-A', 'Card A'),
      makeCard('SKU-B', 'Card B'),
    ]

    // Same seller has both — optimizer pays shipping once, naive pays twice
    const listings: Record<string, BackendListing[]> = {
      'SKU-A': [
        makeListing({ id: 'a1', catalogSku: 'SKU-A', sellerId: 's1', price: 100, sellerName: 'Seller 1' }),
      ],
      'SKU-B': [
        makeListing({ id: 'b1', catalogSku: 'SKU-B', sellerId: 's1', price: 100, sellerName: 'Seller 1' }),
      ],
    }

    const result = optimizeCart(cards, listings, 'cheapest')

    // Naive: card A (100 + 399) + card B (100 + 399) = 998
    expect(result.totalWithoutOptimization).toBe(998)
    // Optimized: 100 + 100 + 399 = 599
    expect(result.totalCost).toBe(599)
    // Savings: 998 - 599 = 399
    expect(result.savings).toBe(399)
  })

  // ── Deduplication ─────────────────────────────────────────────────────────

  it('deduplicates missing cards by catalogSku, summing quantities', () => {
    const cards = [
      makeCard('SKU-A', 'Card A', 2),
      makeCard('SKU-A', 'Card A', 3), // duplicate
    ]

    const listings: Record<string, BackendListing[]> = {
      'SKU-A': [
        makeListing({ id: 'a1', catalogSku: 'SKU-A', sellerId: 's1', price: 100, quantity: 10, sellerName: 'Seller 1' }),
      ],
    }

    const result = optimizeCart(cards, listings, 'cheapest')

    expect(result.totalCards).toBe(5) // 2 + 3 = 5
    expect(result.sellerGroups[0].assignments[0].quantity).toBe(5)
  })

  // ── Performance ───────────────────────────────────────────────────────────

  it('handles 15 cards × 10 sellers per card in < 50ms', () => {
    const cards: MissingCard[] = []
    const listings: Record<string, BackendListing[]> = {}

    for (let c = 0; c < 15; c++) {
      const sku = `SKU-${c.toString().padStart(3, '0')}`
      cards.push(makeCard(sku, `Card ${c}`, 2))
      listings[sku] = []
      for (let s = 0; s < 10; s++) {
        listings[sku].push(
          makeListing({
            id: `l-${c}-${s}`,
            catalogSku: sku,
            sellerId: `seller-${s}`,
            price: 100 + Math.floor(Math.random() * 500),
            quantity: 4,
            sellerName: `Seller ${s}`,
          }),
        )
      }
    }

    const start = performance.now()
    const result = optimizeCart(cards, listings, 'cheapest')
    const elapsed = performance.now() - start

    expect(elapsed).toBeLessThan(50)
    expect(result.totalCards).toBe(30) // 15 * 2
    expect(result.unassignedCards).toHaveLength(0)

    // Also test other modes don't blow up perf
    const start2 = performance.now()
    optimizeCart(cards, listings, 'fewest-sellers')
    const elapsed2 = performance.now() - start2
    expect(elapsed2).toBeLessThan(50)

    const start3 = performance.now()
    optimizeCart(cards, listings, 'best-value')
    const elapsed3 = performance.now() - start3
    expect(elapsed3).toBeLessThan(50)
  })

  // ── Tracked shipping method ───────────────────────────────────────────────

  it('uses tracked shipping cost (599) when listing uses tracked method', () => {
    const cards = [makeCard('SKU-A', 'Card A')]

    const listings: Record<string, BackendListing[]> = {
      'SKU-A': [
        makeListing({
          id: 'a1',
          catalogSku: 'SKU-A',
          sellerId: 's1',
          price: 100,
          shippingMethod: 'tracked',
          sellerName: 'Seller 1',
        }),
      ],
    }

    const result = optimizeCart(cards, listings, 'cheapest')

    expect(result.sellerGroups[0].shippingCost).toBe(599)
    expect(result.totalCost).toBe(100 + 599)
  })

  // ── Explicit shipping cost overrides method ───────────────────────────────

  it('prefers explicit shippingCost over method-derived value', () => {
    const cards = [makeCard('SKU-A', 'Card A')]

    const listings: Record<string, BackendListing[]> = {
      'SKU-A': [
        makeListing({
          id: 'a1',
          catalogSku: 'SKU-A',
          sellerId: 's1',
          price: 100,
          shippingMethod: 'tracked', // would be 599
          shippingCost: 250, // explicit override
          sellerName: 'Seller 1',
        }),
      ],
    }

    const result = optimizeCart(cards, listings, 'cheapest')

    expect(result.sellerGroups[0].shippingCost).toBe(250)
    expect(result.totalCost).toBe(100 + 250)
  })
})

// ─── formatOptimizationSummary ────────────────────────────────────────────────

describe('formatOptimizationSummary', () => {
  it('formats a summary with seller groups and savings', () => {
    const result: OptimizationResult = {
      mode: 'cheapest',
      sellerGroups: [
        {
          sellerId: 's1',
          sellerName: 'CardKingdom',
          assignments: [
            {
              catalogSku: 'SKU-A',
              cardName: 'Lightning Bolt',
              quantity: 4,
              listing: makeListing({ id: 'l1', catalogSku: 'SKU-A', sellerId: 's1', price: 100 }),
            },
          ],
          subtotal: 400,
          shippingCost: 399,
          total: 799,
        },
      ],
      totalCost: 799,
      totalShipping: 399,
      totalCards: 4,
      unassignedCards: [makeCard('SKU-B', 'Counterspell')],
      totalWithoutOptimization: 1996,
      savings: 1197,
      timestamp: Date.now(),
    }

    const summary = formatOptimizationSummary(result)

    expect(summary).toContain('[cart-optimizer]')
    expect(summary).toContain('cheapest')
    expect(summary).toContain('4 cards')
    expect(summary).toContain('1 seller(s)')
    expect(summary).toContain('$7.99')
    expect(summary).toContain('Savings: $11.97')
    expect(summary).toContain('1 card(s) unavailable')
    expect(summary).toContain('Counterspell')
    expect(summary).toContain('CardKingdom')
  })

  it('formats clean summary with no unavailable cards', () => {
    const result: OptimizationResult = {
      mode: 'fewest-sellers',
      sellerGroups: [],
      totalCost: 0,
      totalShipping: 0,
      totalCards: 0,
      unassignedCards: [],
      totalWithoutOptimization: 0,
      savings: 0,
      timestamp: Date.now(),
    }

    const summary = formatOptimizationSummary(result)

    expect(summary).toContain('fewest-sellers')
    expect(summary).not.toContain('unavailable')
  })
})

