it('assigns scarce cards first so greedy does not miss optimal paths', () => {
  // Card A has 1 listing (scarce) — only from s1 at 500
  // Card B has 2 listings — from s1 at 100, from s2 at 150
  // Scarcity-first ensures A (1 listing) processes before B (2 listings).
  // Without scarcity sorting, if B were processed first, it would pick s1 (cheapest),
  // then A would also go to s1 — both get assigned but with different marginal costs.
  // With scarcity sort, A goes first (assigned to s1 with shipping),
  // then B goes to s1 (already in set, no extra shipping) at price 100.
  // This validates that the sort happens (scarce card processed first).
  const cards = [
    makeCard('SKU-B', 'Card B'), // listed first but has more options
    makeCard('SKU-A', 'Card A'), // listed second but scarcer
  ]

  const listings: Record<string, BackendListing[]> = {
    'SKU-A': [
      makeListing({ id: 'a1', catalogSku: 'SKU-A', sellerId: 's1', price: 500, quantity: 1, sellerName: 'Seller 1' }),
    ],
    'SKU-B': [
      makeListing({ id: 'b1', catalogSku: 'SKU-B', sellerId: 's1', price: 100, quantity: 1, sellerName: 'Seller 1' }),
      makeListing({ id: 'b2', catalogSku: 'SKU-B', sellerId: 's2', price: 150, quantity: 1, sellerName: 'Seller 2' }),
    ],
  }

  const result = optimizeCart(cards, listings, 'cheapest')

  expect(result.totalCards).toBe(2)
  expect(result.unassignedCards).toHaveLength(0)

  // Both should end up at s1 (A goes first due to scarcity, B follows since s1 is already in set)
  expect(result.sellerGroups).toHaveLength(1)
  expect(result.sellerGroups[0].sellerId).toBe('s1')

  // Verify A was assigned (it has only 1 listing, would fail if not processed early enough)
  const aAssignment = result.sellerGroups[0].assignments.find(
    (a) => a.catalogSku === 'SKU-A',
  )
  expect(aAssignment).toBeDefined()
  expect(aAssignment!.quantity).toBe(1)
})

